import gmpy2
import binascii
#https://buuoj.cn/challenges#[BJDCTF2020]rsa_output  共模攻击
'''
n = 
c1 = 
c2 = 
e1 = 2767
e2 = 3659
'''



e1=11187289

e2=9647291
s = gmpy2.gcdext(e1, e2)
a = s[1]
b = s[2]
if a < 0:
    a = -a
    c1 = gmpy2.invert(c1, n)
else:
    b = -b
    c2 = gmpy2.invert(c2, n)

m = (gmpy2.powmod(c1, a, n) * gmpy2.powmod(c2, b, n)) % n

print(binascii.unhexlify(hex(m)[2:]))
